import{b as l,J as t,g as r,j as i}from"./chunks/framework.DVAsBjJ_.js";const e="/ibs/assets/screen-layout.DQ-1iqSz.png",g=JSON.parse('{"title":"시작하기","description":"","frontmatter":{},"headers":[],"relativePath":"intro/getting-started.md","filePath":"intro/getting-started.md","lastUpdated":1780909672000}'),o={name:"intro/getting-started.md"};function h(n,a,s,d,u,b){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h1><blockquote><p>IBS Platform은 부동산 개발 프로젝트의 자금, 계약, 고객, 문서, 소송 데이터를 통합 관리하는 시스템입니다. 이 문서는 신규 사용자가 IBS Platform에 접속하고 기본적인 업무를 시작할 수 있도록 안내합니다.</p></blockquote><h2 id="이-문서의-대상" tabindex="-1">이 문서의 대상 <a class="header-anchor" href="#이-문서의-대상" aria-label="Permalink to &quot;이 문서의 대상&quot;">​</a></h2><p>이 문서는 다음 사용자를 대상으로 합니다.</p><ul><li>신규 입사자</li><li>프로젝트 담당자</li><li>회계 및 자금 담당자</li><li>시스템 관리자</li></ul><h2 id="ibs-platform-한눈에-보기" tabindex="-1">IBS Platform 한눈에 보기 <a class="header-anchor" href="#ibs-platform-한눈에-보기" aria-label="Permalink to &quot;IBS Platform 한눈에 보기&quot;">​</a></h2><blockquote><p>IBS Platform은 부동산 개발사업의 전 과정에서 발생하는 데이터를 하나의 시스템에서 통합 관리합니다.</p></blockquote><h3 id="업무-흐름-workflow" tabindex="-1"><strong>업무 흐름 (Workflow)</strong> <a class="header-anchor" href="#업무-흐름-workflow" aria-label="Permalink to &quot;**업무 흐름 (Workflow)**&quot;">​</a></h3><p><strong>프로젝트 관리</strong> ➔ <strong>계약 정보 관리</strong> ➔ <strong>계약 납부 관리</strong> ➔ <strong>회계 자금 관리</strong> ➔ <strong>문서 소송 관리</strong></p><ul><li><strong>프로젝트 관리</strong>: 프로젝트 정보 등록 및 세부설정, 부지관리</li><li><strong>계약 정보 관리</strong>: 계약 등록 및 상세 관리, 권리의무승계, 해지</li><li><strong>계약 납부 관리</strong>: 납부 고지서, SMS 발송 관리</li><li><strong>회계 자금 관리</strong>: 정산, 예산대비 집계, 거래(운영비) 관리</li><li><strong>문서 소송 관리</strong>: 일반/소송 문서, 소송 사건 관리</li></ul><h3 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h3><ul><li>프로젝트 생성 및 기본 정보 설정</li><li>토지 / 토지주 등록 및 매입 계약 관리</li><li>분양 및 임대 계약 관리</li><li>고객 건별 수납 관리 및 집계</li><li>일반 회계 및 자금 관리</li><li>예산 대비 실적 분석</li><li>문서 및 소송 관리</li></ul><h2 id="시스템-접속" tabindex="-1">시스템 접속 <a class="header-anchor" href="#시스템-접속" aria-label="Permalink to &quot;시스템 접속&quot;">​</a></h2><h3 id="접속-주소" tabindex="-1">접속 주소 <a class="header-anchor" href="#접속-주소" aria-label="Permalink to &quot;접속 주소&quot;">​</a></h3><blockquote><p><a href="https://ibs.dyibs.com" target="_blank" rel="noreferrer">https://ibs.dyibs.com</a></p></blockquote><h3 id="계정-생성-및-로그인" tabindex="-1">계정 생성 및 로그인 <a class="header-anchor" href="#계정-생성-및-로그인" aria-label="Permalink to &quot;계정 생성 및 로그인&quot;">​</a></h3><p>시스템 계정을 확보하고 접속하는 방법은 다음 두 가지가 있습니다.</p><h4 id="방법-1-사용자-직접-가입-후-권한-요청" tabindex="-1">방법 1: 사용자 직접 가입 후 권한 요청 <a class="header-anchor" href="#방법-1-사용자-직접-가입-후-권한-요청" aria-label="Permalink to &quot;방법 1: 사용자 직접 가입 후 권한 요청&quot;">​</a></h4><ol><li><strong>직접 가입</strong>: 접속 화면에서 본인이 직접 아이디와 비밀번호를 설정하여 가입을 진행합니다.</li><li><strong>계정 생성코드 입력</strong>: 무분별한 가입 방지를 위해 가입 시 아래의 **계정 생성코드(Register Code)**를 반드시 입력해야 합니다. <ul><li><strong>계정 생성코드: <code>dyibs-staff</code></strong></li><li><em>주의: 계정 생성코드는 사내 보안 사항이므로 외부 유출에 주의하시기 바랍니다.</em></li></ul></li><li><strong>권한 요청</strong>: 가입 완료 후 시스템 관리자에게 해당 계정에 대한 서비스 접속 권한 승인을 요청합니다.</li></ol><h4 id="방법-2-관리자를-통한-계정-생성" tabindex="-1">방법 2: 관리자를 통한 계정 생성 <a class="header-anchor" href="#방법-2-관리자를-통한-계정-생성" aria-label="Permalink to &quot;방법 2: 관리자를 통한 계정 생성&quot;">​</a></h4><ol><li><strong>정보 제공</strong>: 관리자에게 이메일 등 계정 생성에 필요한 정보를 제공합니다.</li><li><strong>계정 수령</strong>: 관리자가 계정을 생성한 후 초기 비밀번호를 부여합니다.</li><li><strong>비밀번호 변경</strong>: 부여받은 초기 비밀번호로 로그인한 후, 반드시 본인의 비밀번호로 변경하여 사용합니다.</li></ol><h3 id="권한-신청" tabindex="-1">권한 신청 <a class="header-anchor" href="#권한-신청" aria-label="Permalink to &quot;권한 신청&quot;">​</a></h3><p>메뉴가 보이지 않거나 접근 권한이 없는 경우 시스템 관리자에게 권한을 요청합니다.</p><h2 id="권장-사용-환경" tabindex="-1">권장 사용 환경 <a class="header-anchor" href="#권장-사용-환경" aria-label="Permalink to &quot;권장 사용 환경&quot;">​</a></h2><h3 id="브라우저" tabindex="-1">브라우저 <a class="header-anchor" href="#브라우저" aria-label="Permalink to &quot;브라우저&quot;">​</a></h3><ul><li>Google Chrome (권장)</li><li>Microsoft Edge</li></ul><h3 id="화면-해상도" tabindex="-1">화면 해상도 <a class="header-anchor" href="#화면-해상도" aria-label="Permalink to &quot;화면 해상도&quot;">​</a></h3><ul><li>최소 1920 * 1080</li></ul><h3 id="브라우저-설정" tabindex="-1">브라우저 설정 <a class="header-anchor" href="#브라우저-설정" aria-label="Permalink to &quot;브라우저 설정&quot;">​</a></h3><ul><li>팝업 허용</li><li>쿠키 허용</li><li>다운로드 차단 해제</li></ul><h2 id="시스템-구성" tabindex="-1">시스템 구성 <a class="header-anchor" href="#시스템-구성" aria-label="Permalink to &quot;시스템 구성&quot;">​</a></h2><h3 id="기술-스택" tabindex="-1">기술 스택 <a class="header-anchor" href="#기술-스택" aria-label="Permalink to &quot;기술 스택&quot;">​</a></h3><table tabindex="0"><thead><tr><th>구분</th><th>구성</th></tr></thead><tbody><tr><td>Frontend</td><td>Vue 3</td></tr><tr><td>Backend</td><td>Django REST Framework</td></tr><tr><td>Database</td><td>PostgreSQL</td></tr><tr><td>Infrastructure</td><td>Kubernetes</td></tr><tr><td>Deployment</td><td>Helm</td></tr></tbody></table><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><p>IBS Platform은 효율적인 업무 처리를 위해 표준화된 레이아웃을 제공합니다.</p><p><img src="'+e+'" alt="화면구성"></p><ul><li><strong>좌측 사이드바 (Navigation)</strong>: 전체 메뉴 및 서비스 이동 기능 제공</li><li><strong>상단 헤더 (Header)</strong>: <ul><li><strong>현재 위치 경로</strong>: 현재 위치 경로 표시 및 바로가기</li><li><strong>전체 화면</strong>: 전체화면 보기 및 일반 브라우저 보기 토글 변경</li><li><strong>테마 전환</strong>: 라이트 모드 및 다크 모드 토글 변경</li><li><strong>사용자 메뉴</strong>: 로그아웃 및 개인 프로필 관리 등</li><li><strong>최근 방문 메뉴</strong>: 최근 작업한 메뉴 바로가기 버튼 제공</li><li><strong>우측 사이드바</strong>: 기타 부가 메뉴 제공</li></ul></li><li><strong>중앙 컨텐츠 (Main Body)</strong>: 실제 업무를 수행하는 입력 폼 및 데이터 목록 영역 <ul><li><strong>회사 또는 프로젝트 선택</strong>: 현재 작업 중인 회사 또는 프로젝트를 즉시 전환</li><li><strong>업무 컨텐츠</strong>: 실제 데이터 조회 및 업무를 수행하는 영역</li></ul></li><li><strong>하단 푸터 (Footer)</strong>: 시스템 정보 및 저작권 표시 영역</li></ul><h2 id="업무-시작-순서" tabindex="-1">업무 시작 순서 <a class="header-anchor" href="#업무-시작-순서" aria-label="Permalink to &quot;업무 시작 순서&quot;">​</a></h2><p>신규 프로젝트를 시작할 때는 일반적으로 다음 순서로 진행합니다.</p><h3 id="_1-프로젝트-등록" tabindex="-1">1. 프로젝트 등록 <a class="header-anchor" href="#_1-프로젝트-등록" aria-label="Permalink to &quot;1. 프로젝트 등록&quot;">​</a></h3><ul><li>프로젝트명, 사업 유형, 시행 기간 등 기본 정보 입력</li></ul><h3 id="_2-프로젝트-세부-설정" tabindex="-1">2. 프로젝트 세부 설정 <a class="header-anchor" href="#_2-프로젝트-세부-설정" aria-label="Permalink to &quot;2. 프로젝트 세부 설정&quot;">​</a></h3><ul><li><strong>차수 타입 설정</strong>: 계약 그룹, 유닛 타입, 층별 타입 등록</li><li><strong>유닛 정보 설정</strong>: 동(건물) 등록, 호수(유닛) 등록</li><li><strong>예산 정보 설정</strong>: 수입/지출 예산 및 산출 근거 등록</li></ul><h3 id="_3-분양-조건-설정" tabindex="-1">3. 분양 조건 설정 <a class="header-anchor" href="#_3-분양-조건-설정" aria-label="Permalink to &quot;3. 분양 조건 설정&quot;">​</a></h3><ul><li>납부 회차, 공급가/계약금, 구비 서류 및 유상 옵션 품목 등록</li></ul><h3 id="_4-부지-정보-관리" tabindex="-1">4. 부지 정보 관리 <a class="header-anchor" href="#_4-부지-정보-관리" aria-label="Permalink to &quot;4. 부지 정보 관리&quot;">​</a></h3><ul><li>사업 부지 필지 정보, 소유자 정보 및 매입 계약 현황 등록</li></ul><h3 id="_5-계약-및-수납-관리" tabindex="-1">5. 계약 및 수납 관리 <a class="header-anchor" href="#_5-계약-및-수납-관리" aria-label="Permalink to &quot;5. 계약 및 수납 관리&quot;">​</a></h3><ul><li><strong>계약 등록</strong>: 고객 정보 및 동호수 매칭</li><li><strong>수납 처리</strong>: 고지서 출력, 입금 등록 및 납부 확인서 생성</li></ul><h3 id="_6-일반-관리-및-분석" tabindex="-1">6. 일반 관리 및 분석 <a class="header-anchor" href="#_6-일반-관리-및-분석" aria-label="Permalink to &quot;6. 일반 관리 및 분석&quot;">​</a></h3><ul><li><strong>자금 관리</strong>: 사업비 집행 및 운영비 관리</li><li><strong>문서 소송</strong>: 일반 문서 및 소송 사건 관리</li><li><strong>보고서 확인</strong>: 예산 실적, 자금 현황, 사업 수지 집계 확인</li></ul><h2 id="빠른-시작-체크리스트" tabindex="-1">빠른 시작 체크리스트 <a class="header-anchor" href="#빠른-시작-체크리스트" aria-label="Permalink to &quot;빠른 시작 체크리스트&quot;">​</a></h2><h3 id="신규-프로젝트-생성" tabindex="-1">신규 프로젝트 생성 <a class="header-anchor" href="#신규-프로젝트-생성" aria-label="Permalink to &quot;신규 프로젝트 생성&quot;">​</a></h3><ul><li><a href="/ibs/project/">프로젝트 등록 가이드</a></li></ul><h3 id="계약-진행" tabindex="-1">계약 진행 <a class="header-anchor" href="#계약-진행" aria-label="Permalink to &quot;계약 진행&quot;">​</a></h3><ul><li><a href="/ibs/contract/">계약 등록 조회 가이드</a></li></ul><h2 id="사용자-권한" tabindex="-1">사용자 권한 <a class="header-anchor" href="#사용자-권한" aria-label="Permalink to &quot;사용자 권한&quot;">​</a></h2><table tabindex="0"><thead><tr><th>역할</th><th>주요 권한</th></tr></thead><tbody><tr><td>시스템 관리자</td><td>전체 관리</td></tr><tr><td>사업관리 담당</td><td>프로젝트, 계약, 수납, 일반문서</td></tr><tr><td>회계 담당</td><td>입출금, 예산</td></tr><tr><td>법무 담당</td><td>소송사건, 소송문서</td></tr><tr><td>임원</td><td>조회 및 보고서</td></tr></tbody></table><h2 id="자주-묻는-질문" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#자주-묻는-질문" aria-label="Permalink to &quot;자주 묻는 질문&quot;">​</a></h2><h3 id="로그인이-되지-않습니다" tabindex="-1">로그인이 되지 않습니다. <a class="header-anchor" href="#로그인이-되지-않습니다" aria-label="Permalink to &quot;로그인이 되지 않습니다.&quot;">​</a></h3><ul><li>아이디/비밀번호 확인</li><li>계정 잠금 여부 확인</li><li>시스템 관리자 문의</li></ul><h3 id="메뉴가-보이지-않습니다" tabindex="-1">메뉴가 보이지 않습니다. <a class="header-anchor" href="#메뉴가-보이지-않습니다" aria-label="Permalink to &quot;메뉴가 보이지 않습니다.&quot;">​</a></h3><ul><li>권한 미부여 가능성</li></ul><h3 id="엑셀-다운로드가-되지-않습니다" tabindex="-1">엑셀 다운로드가 되지 않습니다. <a class="header-anchor" href="#엑셀-다운로드가-되지-않습니다" aria-label="Permalink to &quot;엑셀 다운로드가 되지 않습니다.&quot;">​</a></h3><ul><li>브라우저 팝업 차단 확인</li></ul><h2 id="도움-요청" tabindex="-1">도움 요청 <a class="header-anchor" href="#도움-요청" aria-label="Permalink to &quot;도움 요청&quot;">​</a></h2><h3 id="문의-게시판" tabindex="-1">문의 게시판 <a class="header-anchor" href="#문의-게시판" aria-label="Permalink to &quot;문의 게시판&quot;">​</a></h3><p>시스템 사용 중 발생하는 문의사항이나 오류 보고는 아래 게시판을 이용해 주시기 바랍니다.</p><ul><li><a href="https://ibs.dyibs.com/#/work/project/ibs/boards/1" target="_blank" rel="noreferrer">IBS 문의 게시판 바로가기</a></li></ul><h3 id="시스템-관리자" tabindex="-1">시스템 관리자 <a class="header-anchor" href="#시스템-관리자" aria-label="Permalink to &quot;시스템 관리자&quot;">​</a></h3><ul><li>IT·디지털혁신팀</li></ul><h3 id="문의-유형" tabindex="-1">문의 유형 <a class="header-anchor" href="#문의-유형" aria-label="Permalink to &quot;문의 유형&quot;">​</a></h3><ul><li>계정 생성 및 권한 요청</li><li>오류 신고</li><li>기능 개선 요청</li></ul><h3 id="요청-시-포함-사항" tabindex="-1">요청 시 포함 사항 <a class="header-anchor" href="#요청-시-포함-사항" aria-label="Permalink to &quot;요청 시 포함 사항&quot;">​</a></h3><ul><li>프로젝트명</li><li>메뉴명</li><li>오류 내용</li><li>화면 캡처</li></ul><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><h3 id="사용자-매뉴얼" tabindex="-1">사용자 매뉴얼 <a class="header-anchor" href="#사용자-매뉴얼" aria-label="Permalink to &quot;사용자 매뉴얼&quot;">​</a></h3><ul><li><a href="/ibs/project/">프로젝트 설정</a></li><li><a href="/ibs/contract/">계약 정보 관리</a></li><li><a href="/ibs/payment/">계약 납부 관리</a></li><li><a href="/ibs/notice/bill.html">고객 고지 관리</a></li><li><a href="/ibs/ledger/status.html">회계 자금 관리</a></li><li><a href="/ibs/document/">문서 소송 관리</a></li></ul><h3 id="관리자-매뉴얼" tabindex="-1">관리자 매뉴얼 <a class="header-anchor" href="#관리자-매뉴얼" aria-label="Permalink to &quot;관리자 매뉴얼&quot;">​</a></h3><ul><li><a href="/ibs/authority/">사용자 권한 관리</a></li><li><a href="/ibs/authority/admin-page.html">관리자 페이지</a></li></ul><h3 id="devops-매뉴얼" tabindex="-1">DevOps 매뉴얼 <a class="header-anchor" href="#devops-매뉴얼" aria-label="Permalink to &quot;DevOps 매뉴얼&quot;">​</a></h3><ul><li>시스템 아키텍처</li><li>Kubernetes 운영</li><li>Helm 배포</li><li>PostgreSQL 백업 및 복원</li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>처음 사용하는 경우 아래 순서로 문서를 읽는 것을 권장합니다.</p><ol><li><a href="/ibs/project/">프로젝트 설정</a></li><li><a href="/ibs/contract/">계약 정보 관리</a></li><li><a href="/ibs/payment/">계약 납부 관리</a></li><li><a href="/ibs/ledger/status.html">회계 자금 관리</a></li><li><a href="/ibs/document/">문서 소송 관리</a></li><li><a href="/ibs/notice/bill.html">고객 고지 관리</a></li></ol><p>IBS Platform은 반복적인 관리 업무를 줄이고, 더 나은 의사결정에 집중할 수 있도록 돕는 부동산 개발 운영 플랫폼입니다.</p>',86)])])}const q=l(o,[["render",h]]);export{g as __pageData,q as default};
